{
  "file": "backend/prompts/system_prompt_selftest.py",
  "summary": "This file contains a self-assessment variant of the system prompt used exclusively when StoryForge AI is being evaluated against an SDD that describes changes to its own codebase. The prompt instructs a senior Business Analyst and Solution Architect to analyze the SDD, identify distinct features and requirements, and generate User Stories with Dev Tasks and Unit Test Tasks following strict rules.",
  "rules": [
    {
      "name": "Logical Role Description",
      "description": "Describe affected code by logical role only, never using specific file names or class names.",
      "conditions": ["When describing changes to the codebase"],
      "actions": ["Use generic descriptions like 'the ingestion status endpoint'"]
    },
    {
      "name": "Layer Determination",
      "description": "Determine which layers are affected (frontend, backend, middleware, database) directly from SDD text and context.",
      "conditions": ["When identifying affected components"],
      "actions": ["Specify each layer explicitly or use 'N/A' with justification"]
    },
    {
      "name": "Context Grounding",
      "description": "Ensure `affected_components`, `api_contract`, and other fields are grounded in retrieved codebase context.",
      "conditions": ["When populating these fields"],
      "actions": ["Use relevant chunks from the retrieved context, avoid inventing behavior"]
    },
    {
      "name": "Technical Approach",
      "description": "Provide technical guidance on what needs to change and why without prescribing implementation details.",
      "conditions": ["When describing `technical_approach`"],
      "actions": ["Describe changes at a high level, avoiding specific method/class names or design patterns"]
    },
    {
      "name": "Task Pairing",
      "description": "Ensure each dev task has exactly one corresponding unit test task with matching titles.",
      "conditions": ["When creating tasks"],
      "actions": ["Pair each dev task with a unit test task, referencing the dev task title in the unit test"]
    },
    {
      "name": "Output Format",
      "description": "Respond only with valid JSON matching the specified schema without additional commentary or markdown.",
      "conditions": ["When generating output"],
      "actions": ["Provide ONLY the JSON array described in the prompt"]
    }
  ],
  "dependencies": [
    "config.py",
    "generate.py"
  ]
}
